override suspend fun execute(request: ImageRequest): ImageResult {
    if (!needsExecuteOnMainDispatcher(request)) {
        // Fast path: skip dispatching.
        return execute(request, REQUEST_TYPE_EXECUTE)
    } else {
        // Slow path: dispatch to the main thread.
        return coroutineScope {
            // Start executing the request on the main thread.
            val job = async(options.mainCoroutineContextLazy.value) {
                execute(request, REQUEST_TYPE_EXECUTE)
            }

            // Update the current request attached to the view and await the result.
            getDisposable(request, job).job.await()
        }
    }
}

@VisibleForTesting
    internal fun isCacheValueValid(
        request: ImageRequest,
        cacheKey: MemoryCache.Key,
        cacheValue: MemoryCache.Value,
        size: Size,
        scale: Scale,
    ): Boolean {
        // Ensure we don't return a hardware bitmap if the request doesn't allow it.
        if (!requestService.isCacheValueValidForHardware(request, cacheValue)) {
            logger?.log(TAG, Logger.Level.Debug) {
                "${request.data}: Cached bitmap is hardware-backed, " +
                    "which is incompatible with the request."
            }
            return false
        }

        // Ensure the size of the cached bitmap is valid for the request.
        return isCacheValueValidForSize(request, cacheKey, cacheValue, size, scale)
    }

public data class ParameterRouteSelector(
    override val name: String
) : RouteSelector(), RouteParameterComponent {

    override suspend fun evaluate(context: RoutingResolveContext, segmentIndex: Int): RouteSelectorEvaluation {
        val param = context.call.parameters.getAll(name)
        if (param != null) {
            return RouteSelectorEvaluation.Success(
                RouteSelectorEvaluation.qualityQueryParameter,
                parametersOf(name, param)
            )
        }
        return RouteSelectorEvaluation.FailedParameter
    }

    override fun toString(): String = "[$name]"
}

public data class OptionalParameterRouteSelector(
    override val name: String
) : RouteSelector(), RouteParameterComponent {

    override suspend fun evaluate(context: RoutingResolveContext, segmentIndex: Int): RouteSelectorEvaluation {
        val param = context.call.parameters.getAll(name)
        if (param != null) {
            return RouteSelectorEvaluation.Success(
                RouteSelectorEvaluation.qualityQueryParameter,
                parametersOf(name, param)
            )
        }
        return RouteSelectorEvaluation.Missing
    }

    override fun toString(): String = "[$name?]"
}

public fun Route.createRouteFromPath(path: String): Route {
    val parts = RoutingPath.parse(path).parts
    var current: Route = this
    for (index in parts.indices) {
        val (value, kind) = parts[index]
        val selector = when (kind) {
            RoutingPathSegmentKind.Parameter -> PathSegmentSelectorBuilder.parseParameter(value)
            RoutingPathSegmentKind.Constant -> PathSegmentSelectorBuilder.parseConstant(value)
        }
        // there may already be entry with same selector, so join them
        current = current.createChild(selector)
    }
    if (path.endsWith("/")) {
        current = current.createChild(TrailingSlashRouteSelector)
    }
    return current
}

override fun visitLambdaExpression(lambdaExpression: KtLambdaExpression) {
    super.visitLambdaExpression(lambdaExpression)
    lambdaExpression.valueParameters
        .flatMap { it.getNamedDeclarations() }
        .mapNotNull { it.nameIdentifier }
        .forEach {
            val identifier = it.text
            if (!identifier.matches(parameterPattern)) {
                report(
                    Finding(
                        Entity.from(it),
                        message = "Lambda parameter names should match the pattern: $parameterPattern",
                    )
                )
            }
        }
}

override fun visitParameter(parameter: KtParameter) {
    super.visitParameter(parameter)
    checkNameShadowing(
        parameter,
        // if this param is from lambda or we fallback to function(ctor)
        (parameter.parent.parent.parent as? KtLambdaExpression)
            ?: parameter.parentOfType<KtFunction>(false).let {
                if (it is KtPrimaryConstructor) {
                    // if this param is from primary constructor then pass the class to
                    // start(excluding) the search from
                    parameter.parentOfType<KtClass>(false)
                } else {
                    it
                }
            }
            ?: return,
    )
}

override fun visitCallExpression(expression: KtCallExpression) {
    super.visitCallExpression(expression)

    val className = expression.getCallNameExpression()?.getReferencedName() ?: return
    if (className in arrayTypeDefaultPatterns.keys) {
        val lambdaArgument = expression.valueArguments
            .mapNotNull { it.getArgumentExpression() }
            .filterIsInstance<KtLambdaExpression>()
            .firstOrNull()
            ?: return

        if (hasSideEffects(lambdaArgument)) return

        if (returnsDefaultValue(lambdaArgument, className)) {
            val message = "Unnecessary lambda builder returning default value. Use constructor without lambda."
            report(Finding(Entity.from(expression), message))
        }
    }
}

override suspend fun addIceCandidate(candidate: WebRtc.IceCandidate) {
    val iceCandidate = IceCandidate(
        candidate.sdpMid,
        candidate.sdpMLineIndex,
        candidate.candidate,
    )
    suspendCancellableCoroutine { cont ->
        peerConnection.addIceCandidate(
            iceCandidate,
            object : AddIceObserver {
                override fun onAddSuccess() = cont.resume(Unit)
                override fun onAddFailure(error: String?) = cont.resumeWithException(WebRtc.IceException(error))
            }
        )
    }
}

private fun GQLField.addRequiredFields(
    schema: Schema,
    fragments: Map<String, GQLFragmentDefinition>,
    parentType: String,
): GQLField {
  val typeDefinition = definitionFromScope(schema, parentType)
  if (typeDefinition == null) {
    // This will trigger a validation error later in the build
    return this
  }
  val newSelectionSet = selections.addRequiredFields(
      schema = schema,
      fragments = fragments,
      parentType = typeDefinition.type.rawType().name,
      parentFields = emptySet(),
      isRoot = true
  )

  return copy(
      selections = newSelectionSet,
  )
}

private fun parseFragmentDefinition(start: Token): GQLFragmentDefinition {
  val description = parseDescription()
  expectKeyword("fragment")
  val name = parseFragmentName()
  val variableDefinitions = if (allowFragmentArguments) {
    parseVariableDefinitions()
  } else {
    emptyList()
  }
  expectKeyword("on")
  val typeCondition = parseNamedType()
  val directives = parseDirectives(const = false)
  val selections = parseSelectionSet()
  return GQLFragmentDefinition(
      sourceLocation = sourceLocation(start),
      description = description,
      name = name,
      typeCondition = typeCondition,
      directives = directives,
      selections = selections,
      variableDefinitions = variableDefinitions
  )
}

private fun ValidationScope.validateDirectiveInternal(
    directive: GQLDirective,
    directiveLocation: GQLDirectiveLocation,
    directiveDefinition: GQLDirectiveDefinition,
    registerVariableUsage: (VariableUsage) -> Unit,
) {
  if (directiveLocation !in directiveDefinition.locations) {
    registerIssue(
        message = "Directive '${directive.name}' cannot be applied on '$directiveLocation'",
        sourceLocation = directive.sourceLocation
    )

    return
  }

  validateArguments(
      directive.arguments,
      directive.sourceLocation,
      directiveDefinition.arguments,
      "directive '${directiveDefinition.name}'",
      registerVariableUsage
  )
}

internal fun coerceArgumentValues(
    schema: Schema,
    variableDefinitions: List<GQLVariableDefinition>,
    arguments: List<GQLArgument>,
    coercings: Map<String, Coercing<*>>,
    coercedVariables: Map<String, InternalValue>,
): Map<String, InternalValue> {

  return coerceArgumentValues(schema, coercings, variableDefinitions.map {
    GQLInputValueDefinition(
        sourceLocation = it.sourceLocation,
        description = it.description,
        name = it.name,
        directives = it.directives,
        type = it.type,
        defaultValue = it.defaultValue
    )
  }, arguments, coercedVariables)
}

fun <T: Task> addGeneratedSourceDirectory(
    component: Any,
    taskProvider: TaskProvider<T>,
    wiredWith: (T) -> DirectoryProperty,
    kotlin: Boolean,
) {
  check(component is Component) {
    "Apollo: an instance of com.android.build.api.variant.Component was expected (found '$component')"
  }

  val sources = if (kotlin) {
    component.sources.kotlin ?: error("No Kotlin sources found")
  } else {
    component.sources.java ?: error("No Java sources found")
  }

  // See https://issuetracker.google.com/issues/376709932#comment7
  sources.addGeneratedSourceDirectory(taskProvider, wiredWith)
}

override fun <D : Operation.Data> execute(
    request: ApolloRequest<D>,
): Flow<ApolloResponse<D>> {

  var renewUuid = false

  val flow = callbackFlow {
    val newRequest = if (renewUuid) {
      request.newBuilder().requestUuid(uuid4()).build()
    } else {
      request
    }
    renewUuid = true

    val operationListener = DefaultOperationListener(newRequest, this, parserFactory.createParser(request))

    val webSocket = pool.acquire(newRequest)

    webSocket.startOperation(newRequest, operationListener)

    awaitClose {
      webSocket.stopOperation(newRequest)
    }
  }

  // buffer because we're emitting from websocket callbacks and we can't suspend there
  return flow.buffer(Channel.UNLIMITED)
}

suspend fun Call.Factory.execute(request: Request): Response = suspendCancellableCoroutine { continuation ->
      val call = newCall(request)
      continuation.invokeOnCancellation {
        call.cancel()
      }

      var exception: IOException? = null
      val response = try {
        call.execute()
      } catch (e: IOException) {
        exception = e
        null
      }

      if (exception != null) {
        continuation.resumeWithException(
            ApolloNetworkException(
                message = "Failed to execute GraphQL http network request",
                platformCause = exception
            )
        )
        return@suspendCancellableCoroutine
      } else {
        continuation.resume(response!!)
      }
    }

private fun performTrampolineDispatch() {
  do {
    var task = nextTask()
    while (task != null) {
      task.run()
      task = nextTask()
    }
  } while (
    // We don't dispatch holding the lock so that other tasks can get in on our
    // trampolining time slice, but once we're done, make sure nothing added a new task
    // before we set scheduledDispatch = false, which would prevent the next dispatch
    // from being correctly scheduled. Loop to run these stragglers now.
    synchronized(lock) {
      if (toRunTrampolined.isEmpty()) {
        scheduledTrampolineDispatch = false
        false
      } else {
        true
      }
    }
  )
}

override fun requestDelegate(
    request: ImageRequest,
    job: Job,
    findLifecycle: Boolean,
): RequestDelegate {
    val target = request.target
    if (target is ViewTarget<*>) {
        val lifecycle = request.lifecycle ?: request.findLifecycle()
        return ViewTargetRequestDelegate(imageLoader, request, target, lifecycle, job)
    }

    val lifecycle = request.lifecycle ?: if (findLifecycle) request.findLifecycle() else null
    if (lifecycle != null) {
        return LifecycleRequestDelegate(lifecycle, job)
    }

    return BaseRequestDelegate(job)
}

private fun isConfigValidForHardware(
    request: ImageRequest,
    requestedConfig: Bitmap.Config,
): Boolean {
    // Short circuit if the requested bitmap config is software.
    if (!requestedConfig.isHardware) {
        return true
    }

    // Ensure the request allows hardware bitmaps.
    if (!request.allowHardware) {
        return false
    }

    // Prevent hardware bitmaps for non-hardware accelerated targets.
    val target = request.target
    if (target is ViewTarget<*> &&
        target.view.run { isAttachedToWindow && !isHardwareAccelerated }
    ) {
        return false
    }

    return true
}

internal fun SerialDescriptor.getJsonNameIndex(json: Json, name: String): Int {
    if (json.decodeCaseInsensitive(this)) {
        return getJsonNameIndexSlowPath(json, name.lowercase())
    }

    val strategy = namingStrategy(json)
    if (strategy != null) return getJsonNameIndexSlowPath(json, name)
    val index = getElementIndex(name)
    // Fast path, do not go through ConcurrentHashMap.get
    // Note, it blocks ability to detect collisions between the primary name and alternate,
    // but it eliminates a significant performance penalty (about -15% without this optimization)
    if (index != CompositeDecoder.UNKNOWN_NAME) return index
    if (!json.configuration.useAlternativeNames) return index
    // Slow path
    return getJsonNameIndexSlowPath(json, name)
}

internal fun GQLInterfaceTypeDefinition.toIr(schema: Schema, usedCoordinates: UsedCoordinates, computeKeyArgs: Boolean): IrInterface {
  return IrInterface(
      name = name,
      implements = implementsInterfaces,
      keyFields = schema.keyFields(name).toList(),
      description = description,
      // XXX: this is not spec-compliant. Deprecation directives cannot be on interfaces
      // See https://spec.graphql.org/draft/#sec--deprecated
      deprecationReason = directives.findDeprecationReason(),
      fieldDefinitions = this.fieldDefinitions(schema).filter {
        usedCoordinates.hasField(type = name, field = it.name)
      }.mapNotNull {
        it.toIrFieldDefinition(schema, name, usedCoordinates, computeKeyArgs)
            // Only include fields that have arguments used in operations
            .takeIf { it.argumentDefinitions.isNotEmpty() }
      },
  )
}

internal fun GQLObjectTypeDefinition.toIr(schema: Schema, usedCoordinates: UsedCoordinates, computeKeyArgs: Boolean): IrObject {
  return IrObject(
      name = name,
      implements = implementsInterfaces,
      keyFields = schema.keyFields(name).toList(),
      description = description,
      // XXX: this is not spec-compliant. Directive cannot be on object definitions
      deprecationReason = directives.findDeprecationReason(),
      fieldDefinitions = this.fieldDefinitions(schema).filter {
        usedCoordinates.hasField(type = name, field = it.name)
      }.mapNotNull {
        it.toIrFieldDefinition(schema, name, usedCoordinates, computeKeyArgs)
            // Only include fields that have arguments used in operations
            .takeIf { it.argumentDefinitions.isNotEmpty() }
      },
  )
}

{
  public object Completed : ExitCase() {
    override fun toString(): String =
      "ExitCase.Completed"
  }

  @ConsistentCopyVisibility
  public data class Cancelled internal constructor(val exception: CancellationException) : ExitCase()

  @ConsistentCopyVisibility
  public data class Failure internal constructor(val failure: Throwable) : ExitCase() {
    init {
      require(failure !is CancellationException) { "Failure must not wrap a CancellationException" }
    }
  }

  public companion object {
    public fun ExitCase(error: Throwable): ExitCase =
      if (error is CancellationException) Cancelled(error) else Failure(error)
  }
}

fun Completable.andThen(completable: Completable): Completable =
    completable { emitter ->
        subscribe(
            object : CompletableObserver, ErrorCallback by emitter {
                override fun onSubscribe(disposable: Disposable) {
                    emitter.setDisposable(disposable)
                }

                override fun onComplete() {
                    completable.subscribeSafe(
                        object : CompletableObserver, Observer by this, CompletableCallbacks by emitter {
                        }
                    )
                }
            }
        )
    }

fun Completable.delaySubscription(delay: Duration, scheduler: Scheduler): Completable =
    completable { emitter ->
        val executor = scheduler.newExecutor()
        emitter.setDisposable(executor)

        executor.submit(delay = delay) {
            emitter.tryCatch {
                subscribe(
                    object : CompletableObserver, CompletableCallbacks by emitter {
                        override fun onSubscribe(disposable: Disposable) {
                            emitter.setDisposable(disposable)
                        }
                    }
                )
            }
        }
    }

override fun registry(configure: Action<in Registry>) {
  check(!registered) {
    "Apollo: registry {} cannot be configured outside of a service {} block"
  }

  val registry = objects.newInstance(DefaultRegistry::class.java)

  if (this.registry != null) {
    throw IllegalArgumentException("there must be only one registry block")
  }

  configure.execute(registry)

  if (!registry.graph.isPresent) {
    throw IllegalArgumentException("registry must have a graph")
  }
  if (!registry.key.isPresent) {
    throw IllegalArgumentException("registry must have a key")
  }

  this.registry = registry
}

